const rawOutput = $input.first().json.output || $input.first().json.text || JSON.stringify($input.first().json);

try {
  const parsed = JSON.parse(rawOutput);

  const requiredFields = ['name', 'nodes', 'connections'];

  const missingFields = requiredFields.filter(field => !(field in parsed));

  if (missingFields.length > 0) {
    return [{
      json: {
        valid: false,
        stage: 'required_fields',
        error: `Missing required fields: ${missingFields.join(', ')}`,
        rawOutput
      }
    }];
  }

  // Semantic validation checks
  const workflowString = JSON.stringify(parsed);

  const dangerousPatterns = [
    '"responseBody": "{',
    '"={{ { "'
  ];

  const foundProblems = dangerousPatterns.filter(pattern =>
    workflowString.includes(pattern)
  );

  if (foundProblems.length > 0) {
    return [{
      json: {
        valid: false,
        stage: 'semantic_validation',
        error: `Potential malformed expressions detected`,
        detectedPatterns: foundProblems,
        rawOutput
      }
    }];
  }
// Detect malformed responseBody JSON escaping
for (const node of parsed.nodes || []) {

  if (
    node.parameters &&
    typeof node.parameters.responseBody === 'string'
  ) {

    const body = node.parameters.responseBody;

    // Detect compact malformed JSON expressions
    if (
      body.startsWith('={') &&
      body.includes('"status"') &&
      !body.includes('\\"status\\"')
    ) {

      return [{
        json: {
          valid: false,
          stage: 'responseBody_escape_validation',
          error: 'Malformed responseBody escaping detected',
          rawOutput
        }
      }];
    }
  }
}
  return [{
    json: {
      valid: true,
      workflow: parsed
    }
  }];

} catch (error) {
  return [{
    json: {
      valid: false,
      stage: 'json_parse',
      error: error.message,
      rawOutput
    }
  }];
}

