} catch (error) {
  return [{
    json: {
      valid: false,
      stage: 'json_parse',
      error: error.message,
      rawOutput
    }
  }];
}

const input = $input.first().json;

const workflow = input.workflow;

if (!workflow || !workflow.nodes) {
  return [{
    json: {
      valid: false,
      error: "No workflow object found"
    }
  }];
}

// Traverse all nodes
for (const node of workflow.nodes) {

  if (
    node.parameters &&
    typeof node.parameters.responseBody === 'string'
  ) {

    const body = node.parameters.responseBody;

    // Detect malformed responseBody
    if (
      body.includes('"status"') ||
      body.includes('{"status"')
    ) {

      // FORCE SAFE FORMAT
      node.parameters.responseBody =
        '={\\"status\\":\\"success\\",\\"message\\":\\"Customer data processed successfully\\"}';
    }
  }
}

return [{
  json: {
    valid: true,
    workflow,
    repairApplied: true
  }
}];
